// Revenus Stripe cette semaine
const revenus = $('Récupérer revenus semaine').all();
const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
const recentRevenus = revenus.filter(r => {
  try { return new Date(r.json.date).getTime() > sevenDaysAgo; } catch { return false; }
});
const totalRevenus = recentRevenus.reduce((sum, r) => sum + parseFloat(r.json.montant || 0), 0);

// Ventes Gumroad cette semaine
const ventes = $('Récupérer ventes Gumroad').all();
const recentVentes = ventes.filter(v => {
  try { return new Date(v.json.date).getTime() > sevenDaysAgo; } catch { return false; }
});
const totalVentes = recentVentes.reduce((sum, v) => sum + parseFloat(v.json.montant || 0), 0);

// Stats Beehiiv
const beehiivData = $('Récupérer stats Beehiiv').first().json;
const totalAbonnes = beehiivData.total_results || 0;

// Total
const totalSemaine = totalRevenus + totalVentes;
const weekNum = Math.ceil(new Date().getDate() / 7);

return [{
  json: {
    totalSemaine: totalSemaine.toFixed(2),
    revenus: totalRevenus.toFixed(2),
    ventesGumroad: totalVentes.toFixed(2),
    nbVentes: recentVentes.length,
    nbPaiements: recentRevenus.length,
    totalAbonnes,
    semaine: `S${weekNum}`,
    emoji: totalSemaine > 500 ? '🚀' : totalSemaine > 100 ? '📈' : '🌱'
  }
}];
